class NotificationItem {
  final String id;
  final String title;
  String
  body; // Cambiado a variable para poder actualizar el texto dinámicamente
  final DateTime time;
  bool read;
  final String type; // "reserva", "mensaje", "info"
  final String? reservationId; // Relación con el ID de la tabla en Supabase

  NotificationItem({
    required this.id,
    required this.title,
    required this.body,
    required this.time,
    this.read = false,
    this.type = "info",
    this.reservationId,
  });
}

